import { prisma } from "@/lib/prisma";
import { hashPassword } from "@/lib/hash";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
    try {
        const { username, password, email } = await req.json();

        // 1. Validasi Minimal 8 Karakter
        if (!password || password.length < 8) {
        return NextResponse.json({ error: "Password minimal 8 karakter" }, { status: 400 });
        }

        // 2. Cek apakah username/email sudah ada
        const existingUser = await prisma.user.findFirst({
        where: {
            OR: [{ username }, { email }]
        }
        });

        if (existingUser) {
        return NextResponse.json({ error: "Username atau Email sudah terdaftar" }, { status: 400 });
        }

        // 3. Hash Password dengan SHA-256 dan Simpan
        const user = await prisma.user.create({
        data: {
            username,
            email,
            password: hashPassword(password),
        },
        });

        return NextResponse.json({ message: "User berhasil dibuat", user }, { status: 201 });
    } catch (error) {
        return NextResponse.json({ error: "Terjadi kesalahan server" }, { status: 500 });
    }
}